import{_ as t,o as a,c as o,a3 as s}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"214. Study Leave","description":"","frontmatter":{"title":"214. Study Leave","eba":"Mental Health Services 2024-2028","topics":["leave","study-leave","preliminary","education-pd"]},"headers":[],"relativePath":"ebas/mental-health/management-admin/education-pd/214-study-leave.md","filePath":"ebas/mental-health/management-admin/education-pd/214-study-leave.md"}'),r={name:"ebas/mental-health/management-admin/education-pd/214-study-leave.md"};function n(l,e,i,p,d,u){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="_214-study-leave" tabindex="-1">214. Study Leave <a class="header-anchor" href="#_214-study-leave" aria-label="Permalink to &quot;214. Study Leave&quot;">​</a></h1><p><strong>214.1</strong> Paid study leave will be available to full-time and part-time Employees of up to 4 hours per week for 26 weeks per annum, at the Employer’s discretion.</p><p><strong>214.2</strong> Paid study leave may be taken as mutually agreed by, for example, 4 hours per week, 9 hours per fortnight or blocks of 38 hours at a residential school.</p><p><strong>214.3</strong> A part-time Employee will be entitled to paid study leave on a pro-rata basis.</p><p><strong>214.4</strong> An Employee wishing to take study leave in accordance with this clause must apply in writing to the Employer as early as possible prior to the proposed leave date. The Employee’s request should include details of:</p><p><strong>(a)</strong> the proposed course and institution in which the Employee is enrolled or proposes to enrol; and</p><p><strong>(b)</strong> the relevance of the course to the Employee’s profession.</p><p><strong>214.5</strong> The Employer will notify the Employee of whether their request for study leave has been approved within 7 days of the application being made.</p><p><strong>214.6</strong> Leave pursuant to this clause does not accumulate from year to year.</p><p>Plain language terms: exam leave, education leave.</p>',10)])])}const c=t(r,[["render",n]]);export{h as __pageData,c as default};
